// Loop over input items and add a new field called 'myNewField' to the JSON of each one
// Loop through all input items
for (const item of items) {
  const data = item.json;

  // --- SAFETY CHECK ---
  // If the API returned an error (no 'meta' field), skip processing
  if (!data.meta) {
    item.json.ai_context = `⚠️ API ERROR: ${data.message || 'Unknown error occurred'}`;
    continue; // Stop here for this item and move to the next
  }
  // --------------------

  // 1. Extract Meta Data for context
  const symbol = data.meta.symbol;
  const interval = data.meta.interval;
  const exchange = data.meta.exchange;

  // 2. Start the text block
  let llmText = `### Stock Data: ${symbol} (${exchange})\n`;
  llmText += `Interval: ${interval} | Timezone: ${data.meta.exchange_timezone}\n`;
  llmText += `Format: DateTime | Open | High | Low | Close | Volume\n`;
  llmText += `---\n`;

  // 3. Iterate through values
  if (data.values && Array.isArray(data.values)) {
    data.values.forEach(row => {
      const o = parseFloat(row.open).toFixed(2);
      const h = parseFloat(row.high).toFixed(2);
      const l = parseFloat(row.low).toFixed(2);
      const c = parseFloat(row.close).toFixed(2);
      const v = parseInt(row.volume);

      llmText += `${row.datetime} | ${o} | ${h} | ${l} | ${c} | ${v}\n`;
    });
  }

  // 4. Output the result
  item.json.ai_context = llmText;
}

return items;

// Loop over all incoming items
return items.map(item => {
  // 1. Get the raw string from either 'output' OR 'text' field
  const rawString = item.json.output || item.json.text;

  if (!rawString) {
    throw new Error("No JSON string found in 'output' or 'text' fields!");
  }

  // 2. THE FIX: Extract ONLY the JSON part using Regex
  // This looks for the first '{' and the last '}' and grabs everything in between.
  const jsonMatch = rawString.match(/\{[\s\S]*\}/);

  let parsedData;
  if (jsonMatch) {
    try {
      // Parse only the clean JSON part
      parsedData = JSON.parse(jsonMatch[0]);
    } catch (error) {
      throw new Error("Found JSON-like text but failed to parse it. AI might have returned bad format.");
    }
  } else {
    // If no curly braces found, the AI completely failed
    throw new Error("No JSON object found in the AI response.");
  }

  // 3. Return it structured under "shortTermSentiment"
  return {
    json: {
      shortTermSentiment: parsedData
    }
  };
});

// Loop over input items
return items.map(item => {
  let outputText = "";

  try {
    // 1. LOCATE THE DATA (Handle the specific nesting from your file)
    // Your structure: [ { data: [ {data: [intervals]}, {shortTermSentiment} ] } ]
    const rootData = item.json.data || [];
    const techDataGroup = rootData.find(d => d.data && Array.isArray(d.data));
    const sentimentGroup = rootData.find(d => d.shortTermSentiment);

    // 2. PROCESS TECHNICAL DATA (Candles)
    if (techDataGroup && techDataGroup.data) {
      techDataGroup.data.forEach(dataset => {
        const meta = dataset.meta || {};
        const rows = dataset.values || [];

        // Add Header: "### NVDA 1min"
        outputText += `\nDATASET: ${meta.symbol || 'UNK'} ${meta.interval || ''}\n`;
        outputText += "Time,Open,High,Low,Close,Vol\n";

        // Add Rows (Compressed)
        rows.forEach(r => {
          // Simplify timestamp (keep only time HH:mm:ss if it's intraday to save tokens)
          const timeStr = r.datetime ? r.datetime.split(' ')[1] : r.openTime; 

          // Round prices to 2 decimals
          const o = parseFloat(r.open).toFixed(2);
          const h = parseFloat(r.high).toFixed(2);
          const l = parseFloat(r.low).toFixed(2);
          const c = parseFloat(r.close).toFixed(2);

          // Format: 15:30:00,176.33,176.83,175.91,176.23,3757492
          outputText += `${timeStr},${o},${h},${l},${c},${r.volume}\n`;
        });
      });
    }

    // 3. PROCESS SENTIMENT
    if (sentimentGroup && sentimentGroup.shortTermSentiment) {
      const sent = sentimentGroup.shortTermSentiment;
      outputText += `\n### SENTIMENT REPORT\n`;
      outputText += `Score: ${sent.score} (${sent.category})\n`;
      outputText += `Rationale: ${sent.rationale}\n`;
    }

  } catch (error) {
    outputText += `\nError processing data: ${error.message}`;
  }

  // 4. OUTPUT THE CLEAN "PROMPT-READY" STRING
  return {
    json: {
      cleanData: outputText
    }
  };
});

// Loop over items
return items.map(item => {
  try {
    // --- PART 1: DEEP SEARCH (FIND THE DATA) ---
    const root = item.json.data || item.json;
    let candleDatasets = [];

    if (Array.isArray(root)) {
      if (root.some(d => d.meta && d.meta.interval)) {
        candleDatasets = root;
      } else {
        root.forEach(r => {
            if (r.data && Array.isArray(r.data)) {
                candleDatasets = candleDatasets.concat(r.data);
            }
        });
      }
    }

    const hourlyData = candleDatasets.find(d => d.meta && d.meta.interval === "1h");

    if (!hourlyData || !hourlyData.values) {
      return { json: { error: "No 1h data found." } };
    }

    // --- PART 2: PREPARE DATA ARRAYS ---
    const candles = hourlyData.values.slice(0, 30).reverse();
    const labels = candles.map(c => {
        const time = c.datetime || c.openTime || "";
        return time.includes(' ') ? time.split(' ')[1].slice(0, 5) : time.slice(11, 16);
    });
    const prices = candles.map(c => parseFloat(c.close));

    // Trend Line Calculation
    const avgPrice = prices.reduce((a, b) => a + b, 0) / prices.length;
    const trendLine = Array(prices.length).fill(avgPrice);
    const ticker = hourlyData.meta.symbol || "Unknown";

    // --- PART 3: BUILD THE CHART OBJECT (THE FIX) ---
    const chartConfig = {
      chart: {
        type: "line",
        data: {
          labels: labels,
          datasets: [
            {
              label: ticker + " Price",
              data: prices,
              borderColor: "blue",
              borderWidth: 2,
              fill: false,
              pointRadius: 0
            },
            {
              label: "Trend",
              data: trendLine,
              borderColor: "red",
              borderDash: [5, 5],
              borderWidth: 1,
              pointRadius: 0,
              fill: false
            }
          ]
        },
        options: {
          title: { display: true, text: ticker + " - 1 Hour Trend" },
          legend: { display: false },
          scales: { yAxes: [{ ticks: { fontColor: "black" } }] }
        }
      }
    };

    return {
      json: {
        quickChartPayload: chartConfig 
      }
    };

  } catch (error) {
    return { json: { error: "Script Failed: " + error.message } };
  }
});

// Clean up if the AI adds ```json markers
const raw = $input.first().json.output.replace(/```json/g, "").replace(/```/g, "");
return JSON.parse(raw);

// 1. Get the raw news feed
const response = $input.first().json;
const newsItems = response.feed || [];
const potentialTrades = [];

// Biotech Keywords (Keep these for the safety check)
const biotechTriggers = ['FDA', 'Approved', 'Approval', 'Phase 3', 'Met Primary Endpoint', 'Acquisition'];

for (const story of newsItems) {
  // Skip if no ticker or bad data
  if (!story.ticker_sentiment || story.ticker_sentiment.length === 0) continue;

  const tickerData = story.ticker_sentiment[0];
  const sector = story.topics && story.topics.length > 0 ? story.topics[0].topic : "general";
  const sentiment = parseFloat(tickerData.ticker_sentiment_score);
  const relevance = parseFloat(tickerData.relevance_score); // CRITICAL: We use this now

  // 2. FILTER: Ignore Low Relevance "Fluff"
  // If the article barely mentions the stock (Relevance < 0.8), ignore it completely.
  if (relevance < 0.80) continue; 

  // 3. DEFINE THRESHOLDS
  let threshold = 0.35; 

  if (sector === "life_sciences") {
    const headline = story.title || "";
    const isExplosive = biotechTriggers.some(trigger => headline.includes(trigger));
    threshold = isExplosive ? 0.50 : 0.70;
  }

  // 4. COLLECT (But don't slice yet)
  if (Math.abs(sentiment) > threshold) {
    potentialTrades.push({
      json: {
        ticker: tickerData.ticker,
        sector: sector,
        news_sentiment: sentiment,
        headline: story.title,
        // Calculate a "Quality Score" to rank them later
        quality_score: Math.abs(sentiment) * relevance,
        status: 'WATCHING'
      }
    });
  }
}

// 5. DEDUPLICATE 
const uniqueTrades = Array.from(new Set(potentialTrades.map(a => a.json.ticker)))
    .map(ticker => potentialTrades.find(a => a.json.ticker === ticker));

// 6. SORT BY QUALITY (The Fix)
// Sort by (Sentiment * Relevance) so we get the most RELEVANT stories, not just the loudest.
uniqueTrades.sort((a, b) => b.json.quality_score - a.json.quality_score);

// Return top 5 "High Quality" ideas
return uniqueTrades.slice(0, 5);
